+    fn test_spec_cell_len_algorithm() {
+        // Pure ASCII
+        assert_eq!(cell_len("hello"), 5);
+        assert_eq!(cell_len(""), 0);
+
+        // Pure CJK (each char = 2 cells)
+        assert_eq!(cell_len("日本語"), 6);  // 3 chars * 2 cells
+        assert_eq!(cell_len("中文测试"), 8); // 4 chars * 2 cells
+
+        // Mixed ASCII and CJK
